const themeSwitch=document.querySelector("input");themeSwitch.addEventListener("change",()=>{document.body.classList.toggle("dark-theme")});var tooltipTriggerList=[].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]')),tooltipList=tooltipTriggerList.map((function(tooltipTriggerEl){return new bootstrap.Tooltip(tooltipTriggerEl)}));